import{_ as s,o as a,c as e,f as o}from"./app.cc8f21a4.js";const g=JSON.parse('{"title":"CURL","description":"","frontmatter":{},"headers":[{"level":2,"title":"\u7B80\u4ECB","slug":"\u7B80\u4ECB","link":"#\u7B80\u4ECB","children":[]},{"level":2,"title":"-A","slug":"a","link":"#a","children":[]},{"level":2,"title":"-b","slug":"b","link":"#b","children":[]},{"level":2,"title":"-c","slug":"c","link":"#c","children":[]},{"level":2,"title":"-d","slug":"d","link":"#d","children":[]},{"level":2,"title":"--data-urlencode","slug":"data-urlencode","link":"#data-urlencode","children":[]},{"level":2,"title":"-e","slug":"e","link":"#e","children":[]},{"level":2,"title":"-F","slug":"f","link":"#f","children":[]},{"level":2,"title":"-G","slug":"g","link":"#g","children":[]},{"level":2,"title":"-H","slug":"h","link":"#h","children":[]},{"level":2,"title":"-i","slug":"i","link":"#i","children":[]},{"level":2,"title":"-I","slug":"i-1","link":"#i-1","children":[]},{"level":2,"title":"-k","slug":"k","link":"#k","children":[]},{"level":2,"title":"-L","slug":"l","link":"#l","children":[]},{"level":2,"title":"--limit-rate","slug":"limit-rate","link":"#limit-rate","children":[]},{"level":2,"title":"-o","slug":"o","link":"#o","children":[]},{"level":2,"title":"-O","slug":"o-1","link":"#o-1","children":[]},{"level":2,"title":"-s","slug":"s","link":"#s","children":[]},{"level":2,"title":"-S","slug":"s-1","link":"#s-1","children":[]},{"level":2,"title":"-u","slug":"u","link":"#u","children":[]},{"level":2,"title":"-v","slug":"v","link":"#v","children":[]},{"level":2,"title":"-x","slug":"x","link":"#x","children":[]},{"level":2,"title":"-X","slug":"x-1","link":"#x-1","children":[]}],"relativePath":"contents/Backend/Linux/curl.md"}'),l={name:"contents/Backend/Linux/curl.md"},n=o(`<h1 id="curl" tabindex="-1">CURL <a class="header-anchor" href="#curl" aria-hidden="true">#</a></h1><h2 id="\u7B80\u4ECB" tabindex="-1">\u7B80\u4ECB <a class="header-anchor" href="#\u7B80\u4ECB" aria-hidden="true">#</a></h2><p>curl \u662F\u5E38\u7528\u7684\u547D\u4EE4\u884C\u5DE5\u5177\uFF0C\u7528\u6765\u8BF7\u6C42 Web \u670D\u52A1\u5668\u3002\u5B83\u7684\u540D\u5B57\u5C31\u662F\u5BA2\u6237\u7AEF\uFF08client\uFF09\u7684 URL \u5DE5\u5177\u7684\u610F\u601D\u3002</p><p>\u5B83\u7684\u529F\u80FD\u975E\u5E38\u5F3A\u5927\uFF0C\u547D\u4EE4\u884C\u53C2\u6570\u591A\u8FBE\u51E0\u5341\u79CD\u3002\u5982\u679C\u719F\u7EC3\u7684\u8BDD\uFF0C\u5B8C\u5168\u53EF\u4EE5\u53D6\u4EE3 Postman \u8FD9\u4E00\u7C7B\u7684\u56FE\u5F62\u754C\u9762\u5DE5\u5177\u3002</p><p>\u4E0D\u5E26\u6709\u4EFB\u4F55\u53C2\u6570\u65F6\uFF0Ccurl \u5C31\u662F\u53D1\u51FA GET \u8BF7\u6C42\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u5411<code>www.example.com</code>\u53D1\u51FA GET \u8BF7\u6C42\uFF0C\u670D\u52A1\u5668\u8FD4\u56DE\u7684\u5185\u5BB9\u4F1A\u5728\u547D\u4EE4\u884C\u8F93\u51FA\u3002</p><h2 id="a" tabindex="-1"><strong>-A</strong> <a class="header-anchor" href="#a" aria-hidden="true">#</a></h2><p><code>-A</code>\u53C2\u6570\u6307\u5B9A\u5BA2\u6237\u7AEF\u7684\u7528\u6237\u4EE3\u7406\u6807\u5934\uFF0C\u5373<code>User-Agent</code>\u3002curl \u7684\u9ED8\u8BA4\u7528\u6237\u4EE3\u7406\u5B57\u7B26\u4E32\u662F<code>curl/[version]</code>\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -A </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/76.0.3809.100 Safari/537.36</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u5C06<code>User-Agent</code>\u6539\u6210 Chrome \u6D4F\u89C8\u5668\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -A </span><span style="color:#89DDFF;">&#39;&#39;</span><span style="color:#A6ACCD;"> https://google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u4F1A\u79FB\u9664<code>User-Agent</code>\u6807\u5934\u3002</p><p>\u4E5F\u53EF\u4EE5\u901A\u8FC7<code>-H</code>\u53C2\u6570\u76F4\u63A5\u6307\u5B9A\u6807\u5934\uFF0C\u66F4\u6539<code>User-Agent</code>\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -H </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">User-Agent: php/1.0</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><h2 id="b" tabindex="-1"><strong>-b</strong> <a class="header-anchor" href="#b" aria-hidden="true">#</a></h2><p><code>-b</code>\u53C2\u6570\u7528\u6765\u5411\u670D\u52A1\u5668\u53D1\u9001 Cookie\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -b </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">foo=bar</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u4F1A\u751F\u6210\u4E00\u4E2A\u6807\u5934<code>Cookie: foo=bar</code>\uFF0C\u5411\u670D\u52A1\u5668\u53D1\u9001\u4E00\u4E2A\u540D\u4E3A<code>foo</code>\u3001\u503C\u4E3A<code>bar</code>\u7684 Cookie\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -b </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">foo1=bar;foo2=bar2</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u53D1\u9001\u4E24\u4E2A Cookie\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -b cookies.txt https://www.google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u8BFB\u53D6\u672C\u5730\u6587\u4EF6<code>cookies.txt</code>\uFF0C\u91CC\u9762\u662F\u670D\u52A1\u5668\u8BBE\u7F6E\u7684 Cookie\uFF08\u53C2\u89C1<code>-c</code>\u53C2\u6570\uFF09\uFF0C\u5C06\u5176\u53D1\u9001\u5230\u670D\u52A1\u5668\u3002</p><h2 id="c" tabindex="-1"><strong>-c</strong> <a class="header-anchor" href="#c" aria-hidden="true">#</a></h2><p><code>-c</code>\u53C2\u6570\u5C06\u670D\u52A1\u5668\u8BBE\u7F6E\u7684 Cookie \u5199\u5165\u4E00\u4E2A\u6587\u4EF6\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -c cookies.txt https://www.google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u5C06\u670D\u52A1\u5668\u7684 HTTP \u56DE\u5E94\u6240\u8BBE\u7F6E Cookie \u5199\u5165\u6587\u672C\u6587\u4EF6<code>cookies.txt</code>\u3002</p><h2 id="d" tabindex="-1"><strong>-d</strong> <a class="header-anchor" href="#d" aria-hidden="true">#</a></h2><p><code>-d</code>\u53C2\u6570\u7528\u4E8E\u53D1\u9001 POST \u8BF7\u6C42\u7684\u6570\u636E\u4F53\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -d</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">login=emma\uFF06password=123</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;">-X POST https://google.com/login</span></span>
<span class="line"><span style="color:#676E95;"># \u6216\u8005</span></span>
<span class="line"><span style="color:#A6ACCD;">$ curl -d </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">login=emma</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> -d </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">password=123</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> -X POST  https://google.com/login</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4F7F\u7528<code>-d</code>\u53C2\u6570\u4EE5\u540E\uFF0CHTTP \u8BF7\u6C42\u4F1A\u81EA\u52A8\u52A0\u4E0A\u6807\u5934<code>Content-Type : application/x-www-form-urlencoded</code>\u3002\u5E76\u4E14\u4F1A\u81EA\u52A8\u5C06\u8BF7\u6C42\u8F6C\u4E3A POST \u65B9\u6CD5\uFF0C\u56E0\u6B64\u53EF\u4EE5\u7701\u7565<code>-X POST</code>\u3002</p><p><code>-d</code>\u53C2\u6570\u53EF\u4EE5\u8BFB\u53D6\u672C\u5730\u6587\u672C\u6587\u4EF6\u7684\u6570\u636E\uFF0C\u5411\u670D\u52A1\u5668\u53D1\u9001\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -d </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">@data.txt</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com/login</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u8BFB\u53D6<code>data.txt</code>\u6587\u4EF6\u7684\u5185\u5BB9\uFF0C\u4F5C\u4E3A\u6570\u636E\u4F53\u5411\u670D\u52A1\u5668\u53D1\u9001\u3002</p><h2 id="data-urlencode" tabindex="-1"><strong>--data-urlencode</strong> <a class="header-anchor" href="#data-urlencode" aria-hidden="true">#</a></h2><p><code>--data-urlencode</code>\u53C2\u6570\u7B49\u540C\u4E8E<code>-d</code>\uFF0C\u53D1\u9001 POST \u8BF7\u6C42\u7684\u6570\u636E\u4F53\uFF0C\u533A\u522B\u5728\u4E8E\u4F1A\u81EA\u52A8\u5C06\u53D1\u9001\u7684\u6570\u636E\u8FDB\u884C URL \u7F16\u7801\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl --data-urlencode </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">comment=hello world</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com/login</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u4EE3\u7801\u4E2D\uFF0C\u53D1\u9001\u7684\u6570\u636E<code>hello world</code>\u4E4B\u95F4\u6709\u4E00\u4E2A\u7A7A\u683C\uFF0C\u9700\u8981\u8FDB\u884C URL \u7F16\u7801\u3002</p><h2 id="e" tabindex="-1"><strong>-e</strong> <a class="header-anchor" href="#e" aria-hidden="true">#</a></h2><p><code>-e</code>\u53C2\u6570\u7528\u6765\u8BBE\u7F6E HTTP \u7684\u6807\u5934<code>Referer</code>\uFF0C\u8868\u793A\u8BF7\u6C42\u7684\u6765\u6E90\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">curl -e </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">https://google.com?q=example</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u5C06<code>Referer</code>\u6807\u5934\u8BBE\u4E3A<code>https://google.com?q=example</code>\u3002</p><p><code>-H</code>\u53C2\u6570\u53EF\u4EE5\u901A\u8FC7\u76F4\u63A5\u6DFB\u52A0\u6807\u5934<code>Referer</code>\uFF0C\u8FBE\u5230\u540C\u6837\u6548\u679C\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">curl -H </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Referer: https://google.com?q=example</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><h2 id="f" tabindex="-1"><strong>-F</strong> <a class="header-anchor" href="#f" aria-hidden="true">#</a></h2><p><code>-F</code>\u53C2\u6570\u7528\u6765\u5411\u670D\u52A1\u5668\u4E0A\u4F20\u4E8C\u8FDB\u5236\u6587\u4EF6\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -F </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">file=@photo.png</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com/profile</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u4F1A\u7ED9 HTTP \u8BF7\u6C42\u52A0\u4E0A\u6807\u5934<code>Content-Type: multipart/form-data</code>\uFF0C\u7136\u540E\u5C06\u6587\u4EF6<code>photo.png</code>\u4F5C\u4E3A<code>file</code>\u5B57\u6BB5\u4E0A\u4F20\u3002</p><p><code>-F</code>\u53C2\u6570\u53EF\u4EE5\u6307\u5B9A MIME \u7C7B\u578B\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -F </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">file=@photo.png;type=image/png</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com/profile</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u6307\u5B9A MIME \u7C7B\u578B\u4E3A<code>image/png</code>\uFF0C\u5426\u5219 curl \u4F1A\u628A MIME \u7C7B\u578B\u8BBE\u4E3A<code>application/octet-stream</code>\u3002</p><p><code>-F</code>\u53C2\u6570\u4E5F\u53EF\u4EE5\u6307\u5B9A\u6587\u4EF6\u540D\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -F </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">file=@photo.png;filename=me.png</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com/profile</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u4E2D\uFF0C\u539F\u59CB\u6587\u4EF6\u540D\u4E3A<code>photo.png</code>\uFF0C\u4F46\u662F\u670D\u52A1\u5668\u63A5\u6536\u5230\u7684\u6587\u4EF6\u540D\u4E3A<code>me.png</code>\u3002</p><h2 id="g" tabindex="-1"><strong>-G</strong> <a class="header-anchor" href="#g" aria-hidden="true">#</a></h2><p><code>-G</code>\u53C2\u6570\u7528\u6765\u6784\u9020 URL \u7684\u67E5\u8BE2\u5B57\u7B26\u4E32\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -G -d </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">q=kitties</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> -d </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">count=20</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com/search</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u4F1A\u53D1\u51FA\u4E00\u4E2A GET \u8BF7\u6C42\uFF0C\u5B9E\u9645\u8BF7\u6C42\u7684 URL \u4E3A<code>https://google.com/search?q=kitties&amp;count=20</code>\u3002\u5982\u679C\u7701\u7565<code>--G</code>\uFF0C\u4F1A\u53D1\u51FA\u4E00\u4E2A POST \u8BF7\u6C42\u3002</p><p>\u5982\u679C\u6570\u636E\u9700\u8981 URL \u7F16\u7801\uFF0C\u53EF\u4EE5\u7ED3\u5408<code>--data--urlencode</code>\u53C2\u6570\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -G --data-urlencode </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">comment=hello world</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><h2 id="h" tabindex="-1"><strong>-H</strong> <a class="header-anchor" href="#h" aria-hidden="true">#</a></h2><p><code>-H</code>\u53C2\u6570\u6DFB\u52A0 HTTP \u8BF7\u6C42\u7684\u6807\u5934\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -H </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Accept-Language: en-US</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u6DFB\u52A0 HTTP \u6807\u5934<code>Accept-Language: en-US</code>\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -H </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Accept-Language: en-US</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> -H </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Secret-Message: xyzzy</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u6DFB\u52A0\u4E24\u4E2A HTTP \u6807\u5934\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -d </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">{&quot;login&quot;: &quot;emma&quot;, &quot;pass&quot;: &quot;123&quot;}</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> -H </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Content-Type: application/json</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com/login</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u6DFB\u52A0 HTTP \u8BF7\u6C42\u7684\u6807\u5934\u662F<code>Content-Type: application/json</code>\uFF0C\u7136\u540E\u7528<code>-d</code>\u53C2\u6570\u53D1\u9001 JSON \u6570\u636E\u3002</p><h2 id="i" tabindex="-1"><strong>-i</strong> <a class="header-anchor" href="#i" aria-hidden="true">#</a></h2><p><code>-i</code>\u53C2\u6570\u6253\u5370\u51FA\u670D\u52A1\u5668\u56DE\u5E94\u7684 HTTP \u6807\u5934\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -i https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u6536\u5230\u670D\u52A1\u5668\u56DE\u5E94\u540E\uFF0C\u5148\u8F93\u51FA\u670D\u52A1\u5668\u56DE\u5E94\u7684\u6807\u5934\uFF0C\u7136\u540E\u7A7A\u4E00\u884C\uFF0C\u518D\u8F93\u51FA\u7F51\u9875\u7684\u6E90\u7801\u3002</p><h2 id="i-1" tabindex="-1"><strong>-I</strong> <a class="header-anchor" href="#i-1" aria-hidden="true">#</a></h2><p><code>-I</code>\u53C2\u6570\u5411\u670D\u52A1\u5668\u53D1\u51FA HEAD \u8BF7\u6C42\uFF0C\u7136\u4F1A\u5C06\u670D\u52A1\u5668\u8FD4\u56DE\u7684 HTTP \u6807\u5934\u6253\u5370\u51FA\u6765\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -I https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u8F93\u51FA\u670D\u52A1\u5668\u5BF9 HEAD \u8BF7\u6C42\u7684\u56DE\u5E94\u3002</p><p><code>--head</code>\u53C2\u6570\u7B49\u540C\u4E8E<code>-I</code>\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl --head https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><h2 id="k" tabindex="-1"><strong>-k</strong> <a class="header-anchor" href="#k" aria-hidden="true">#</a></h2><p><code>-k</code>\u53C2\u6570\u6307\u5B9A\u8DF3\u8FC7 SSL \u68C0\u6D4B\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -k https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u4E0D\u4F1A\u68C0\u67E5\u670D\u52A1\u5668\u7684 SSL \u8BC1\u4E66\u662F\u5426\u6B63\u786E\u3002</p><h2 id="l" tabindex="-1"><strong>-L</strong> <a class="header-anchor" href="#l" aria-hidden="true">#</a></h2><p><code>-L</code>\u53C2\u6570\u4F1A\u8BA9 HTTP \u8BF7\u6C42\u8DDF\u968F\u670D\u52A1\u5668\u7684\u91CD\u5B9A\u5411\u3002curl \u9ED8\u8BA4\u4E0D\u8DDF\u968F\u91CD\u5B9A\u5411\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -L -d </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">tweet=hi</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://api.twitter.com/tweet</span></span>
<span class="line"></span></code></pre></div></blockquote><h2 id="limit-rate" tabindex="-1"><strong>--limit-rate</strong> <a class="header-anchor" href="#limit-rate" aria-hidden="true">#</a></h2><p><code>--limit-rate</code>\u7528\u6765\u9650\u5236 HTTP \u8BF7\u6C42\u548C\u56DE\u5E94\u7684\u5E26\u5BBD\uFF0C\u6A21\u62DF\u6162\u7F51\u901F\u7684\u73AF\u5883\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl --limit-rate 200k https://google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u5C06\u5E26\u5BBD\u9650\u5236\u5728\u6BCF\u79D2 200K \u5B57\u8282\u3002</p><h2 id="o" tabindex="-1"><strong>-o</strong> <a class="header-anchor" href="#o" aria-hidden="true">#</a></h2><p><code>-o</code>\u53C2\u6570\u5C06\u670D\u52A1\u5668\u7684\u56DE\u5E94\u4FDD\u5B58\u6210\u6587\u4EF6\uFF0C\u7B49\u540C\u4E8E<code>wget</code>\u547D\u4EE4\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -o example.html https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u5C06<code>www.example.com</code>\u4FDD\u5B58\u6210<code>example.html</code>\u3002</p><h2 id="o-1" tabindex="-1"><strong>-O</strong> <a class="header-anchor" href="#o-1" aria-hidden="true">#</a></h2><p><code>-O</code>\u53C2\u6570\u5C06\u670D\u52A1\u5668\u56DE\u5E94\u4FDD\u5B58\u6210\u6587\u4EF6\uFF0C\u5E76\u5C06 URL \u7684\u6700\u540E\u90E8\u5206\u5F53\u4F5C\u6587\u4EF6\u540D\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -O https://www.example.com/foo/bar.html</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u5C06\u670D\u52A1\u5668\u56DE\u5E94\u4FDD\u5B58\u6210\u6587\u4EF6\uFF0C\u6587\u4EF6\u540D\u4E3A<code>bar.html</code>\u3002</p><h2 id="s" tabindex="-1"><strong>-s</strong> <a class="header-anchor" href="#s" aria-hidden="true">#</a></h2><p><code>-s</code>\u53C2\u6570\u5C06\u4E0D\u8F93\u51FA\u9519\u8BEF\u548C\u8FDB\u5EA6\u4FE1\u606F\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -s https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u4E00\u65E6\u53D1\u751F\u9519\u8BEF\uFF0C\u4E0D\u4F1A\u663E\u793A\u9519\u8BEF\u4FE1\u606F\u3002\u4E0D\u53D1\u751F\u9519\u8BEF\u7684\u8BDD\uFF0C\u4F1A\u6B63\u5E38\u663E\u793A\u8FD0\u884C\u7ED3\u679C\u3002</p><p>\u5982\u679C\u60F3\u8BA9 curl \u4E0D\u4EA7\u751F\u4EFB\u4F55\u8F93\u51FA\uFF0C\u53EF\u4EE5\u4F7F\u7528\u4E0B\u9762\u7684\u547D\u4EE4\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -s -o /dev/null https://google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><h2 id="s-1" tabindex="-1"><strong>-S</strong> <a class="header-anchor" href="#s-1" aria-hidden="true">#</a></h2><p><code>-S</code>\u53C2\u6570\u6307\u5B9A\u53EA\u8F93\u51FA\u9519\u8BEF\u4FE1\u606F\uFF0C\u901A\u5E38\u4E0E<code>-s</code>\u4E00\u8D77\u4F7F\u7528\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -s -o /dev/null https://google.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u6CA1\u6709\u4EFB\u4F55\u8F93\u51FA\uFF0C\u9664\u975E\u53D1\u751F\u9519\u8BEF\u3002</p><h2 id="u" tabindex="-1"><strong>-u</strong> <a class="header-anchor" href="#u" aria-hidden="true">#</a></h2><p><code>-u</code>\u53C2\u6570\u7528\u6765\u8BBE\u7F6E\u670D\u52A1\u5668\u8BA4\u8BC1\u7684\u7528\u6237\u540D\u548C\u5BC6\u7801\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -u </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">bob:12345</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com/login</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u8BBE\u7F6E\u7528\u6237\u540D\u4E3A<code>bob</code>\uFF0C\u5BC6\u7801\u4E3A<code>12345</code>\uFF0C\u7136\u540E\u5C06\u5176\u8F6C\u4E3A HTTP \u6807\u5934<code>Authorization: Basic Ym9iOjEyMzQ1</code>\u3002</p><p>curl \u80FD\u591F\u8BC6\u522B URL \u91CC\u9762\u7684\u7528\u6237\u540D\u548C\u5BC6\u7801\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl https://bob:12345@google.com/login</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u80FD\u591F\u8BC6\u522B URL \u91CC\u9762\u7684\u7528\u6237\u540D\u548C\u5BC6\u7801\uFF0C\u5C06\u5176\u8F6C\u4E3A\u4E0A\u4E2A\u4F8B\u5B50\u91CC\u9762\u7684 HTTP \u6807\u5934\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -u </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">bob</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> https://google.com/login</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u53EA\u8BBE\u7F6E\u4E86\u7528\u6237\u540D\uFF0C\u6267\u884C\u540E\uFF0Ccurl \u4F1A\u63D0\u793A\u7528\u6237\u8F93\u5165\u5BC6\u7801\u3002</p><h2 id="v" tabindex="-1"><strong>-v</strong> <a class="header-anchor" href="#v" aria-hidden="true">#</a></h2><p><code>-v</code>\u53C2\u6570\u8F93\u51FA\u901A\u4FE1\u7684\u6574\u4E2A\u8FC7\u7A0B\uFF0C\u7528\u4E8E\u8C03\u8BD5\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -v https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p><code>--trace</code>\u53C2\u6570\u4E5F\u53EF\u4EE5\u7528\u4E8E\u8C03\u8BD5\uFF0C\u8FD8\u4F1A\u8F93\u51FA\u539F\u59CB\u7684\u4E8C\u8FDB\u5236\u6570\u636E\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl --trace - https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><h2 id="x" tabindex="-1"><strong>-x</strong> <a class="header-anchor" href="#x" aria-hidden="true">#</a></h2><p><code>-x</code>\u53C2\u6570\u6307\u5B9A HTTP \u8BF7\u6C42\u7684\u4EE3\u7406\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -x socks5://james:cats@myproxy.com:8080 https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u6307\u5B9A HTTP \u8BF7\u6C42\u901A\u8FC7<code>myproxy.com:8080</code>\u7684 socks5 \u4EE3\u7406\u53D1\u51FA\u3002</p><p>\u5982\u679C\u6CA1\u6709\u6307\u5B9A\u4EE3\u7406\u534F\u8BAE\uFF0C\u9ED8\u8BA4\u4E3A HTTP\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -x james:cats@myproxy.com:8080 https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u4E2D\uFF0C\u8BF7\u6C42\u7684\u4EE3\u7406\u4F7F\u7528 HTTP \u534F\u8BAE\u3002</p><h2 id="x-1" tabindex="-1"><strong>-X</strong> <a class="header-anchor" href="#x-1" aria-hidden="true">#</a></h2><p><code>-X</code>\u53C2\u6570\u6307\u5B9A HTTP \u8BF7\u6C42\u7684\u65B9\u6CD5\u3002</p><blockquote><div class="language-bash"><button class="copy"></button><span class="lang">bash</span><pre><code><span class="line"><span style="color:#A6ACCD;">$ curl -X POST https://www.example.com</span></span>
<span class="line"></span></code></pre></div></blockquote><p>\u4E0A\u9762\u547D\u4EE4\u5BF9<code>https://www.example.com</code>\u53D1\u51FA POST \u8BF7\u6C42\u3002</p>`,132),c=[n];function p(t,r,d,i,u,h){return a(),e("div",null,c)}const y=s(l,[["render",p]]);export{g as __pageData,y as default};
